  function applySectionLocks(){ var locks=loadLocks(); document.querySelectorAll('.section').forEach(function(sec){ var header=sec.querySelector('.section-header'); if(header && !header.querySelector('.section-lock-btn')){ var btn=document.createElement('button'); btn.type='button'; btn.className='section-lock-btn'; btn.textContent='Lock section'; header.appendChild(btn); btn.addEventListener('click', function(){ var map=loadLocks(); map[sec.id]=!map[sec.id]; saveLocks(map); addHistory('lock', (map[sec.id]?'Section locked':'Section unlocked'), {sectionId:sec.id}); markDirty('lock'); applySectionLocks(); }); }
      var btn=header&&header.querySelector('.section-lock-btn'); var locked=!!locks[sec.id]; sec.dataset.locked=locked?'1':'0'; if(btn){ btn.classList.toggle('locked',locked); btn.textContent=locked?'Unlock section':'Lock section'; }
      var ind=header&&header.querySelector('.lock-indicator'); if(locked && !ind){ ind=document.createElement('span'); ind.className='lock-indicator'; ind.textContent='Locked'; header.appendChild(ind); } if(!locked && ind) ind.remove();
      sec.querySelectorAll('[data-master-edit-enabled="1"]').forEach(function(el){ if(locked){ el.contentEditable='false'; el.dataset.lockedBySection='1'; } else if(document.body.classList.contains('bld-on')) { el.contentEditable='true'; el.removeAttribute('data-locked-by-section'); } });
    }); }
